/**
 * ========== 处理数据 ===========
 * 时间戳转换 ；赋值给临时变量
 * @param {number} timestamp 10位秒 / 13位毫秒时间戳
 * @returns {{date: string, time: string}}
 */
function splitTsToDateObj(timestamp) {
  if (!timestamp) {
    return "";
  };
  // 兼容10位秒级时间戳，统一转毫秒
  const ts = String(timestamp).length === 10 ? timestamp * 1000 : timestamp;
  const d = new Date(ts);

  // 补零工具
  const pad = n => n.toString().padStart(2, '0');

  const year = d.getFullYear();
  const month = pad(d.getMonth() + 1);
  const day = pad(d.getDate());

  const hour = pad(d.getHours());
  const min = pad(d.getMinutes());
  const sec = pad(d.getSeconds());

  return `${year}-${month}-${day} ${hour}:${min}:${sec}`;
};


/**
 * 纯本地解析文件链接，无网络请求
 * @param {string} url 文件地址
 * @returns {
 *   fileName: string,      // 完整文件名
 *   suffix: string,        // 小写后缀
 *   category: string      // 文件分类：图片 / 文档 / 未知
 * }
 */
function parseFileUrlLocal(url) {
  if (!url) {
    return "";
  };
  // 取最后一段文件名
  const fileName = url.split('/').pop();
  const arr = fileName.split('.');
  const suffix = arr.length >= 2 ? arr.pop().toLowerCase() : '';

  let category = '未知';

  // 图片后缀集合
  const imgExt = ['png', 'jpg', 'jpeg', 'gif', 'bmp', 'webp', 'svg'];
  // File文档
  const fileExt = ['doc', 'docx', 'pdf', 'xls', 'xlsx'];

  if (imgExt.includes(suffix)) {
    category = "image";
  } else if (fileExt.includes(suffix)) {
    category = "file";
  }

  return {
    "fileName": fileName,
    "url": url,
    "category": category
  };
};

